/**
 * Spec 工作流数据模型
 * 定义状态枚举、阶段定义、工作流上下文、用户操作等
 */

// ============ 工作流状态 ============

export enum WorkflowStatus {
  IDLE = "idle",
  RUNNING = "running",
  WAITING_FOR_USER = "waiting_for_user",
  COMPLETED = "completed",
  FAILED = "failed",
  ABORTED = "aborted",
}

// ============ 阶段定义 ============

export type PhaseId = "specification" | "design" | "planning" | "execution" | "compilation_fix" | "summary";

export enum PhaseStatus {
  PENDING = "pending",
  RUNNING = "running",
  COMPLETED = "completed",
  FAILED = "failed",
  SKIPPED = "skipped",
}

export interface PhaseDefinition {
  id: PhaseId;
  name: string;
  description: string;
  order: number;
  /** 该阶段允许使用的工具名称列表 */
  allowedTools: string[];
  /** 该阶段的 prompt 模板名称 */
  promptTemplate: string;
  /** 该阶段的契约文件名 */
  artifactFileName: string;
}

// ============ 阶段结果 ============

export interface PhaseResult {
  phaseId: PhaseId;
  status: PhaseStatus;
  output: string;
  artifactPath?: string;
  tokenUsage: { input: number; output: number };
  startTime: number;
  endTime?: number;
}

// ============ 选中的 Skill ============

export interface SelectedSkill {
  name: string;
  description: string;
  content: string;
  appliesTo: PhaseId[];
}

// ============ 工作流上下文 ============

export interface FeedbackMessage {
  role: "user" | "assistant";
  content: string;
}

export interface WorkflowContext {
  sessionId: string;
  turnId: string;
  userQuery: string;
  workspacePath: string;
  /** 各阶段结果 */
  phaseResults: Map<PhaseId, PhaseResult>;
  /** 已执行阶段顺序 */
  executionHistory: PhaseId[];
  /** 契约文件存放目录 */
  specDir: string;
  /** 取消信号 */
  signal?: AbortSignal;
  /** 各阶段的反馈对话历史（阶段完成后的连续对话） */
  feedbackHistory: Map<PhaseId, FeedbackMessage[]>;
  /** LLM 选中的 skills（在工作流启动时匹配） */
  selectedSkills: SelectedSkill[];
}

// ============ 用户操作 ============

export type UserAction =
  | { type: "next_phase" }
  | { type: "rollback"; targetPhase: PhaseId }
  | { type: "edit"; feedback?: string }
  | { type: "feedback"; message: string; turnId?: string }
  | { type: "abort" }
  | { type: "complete_workflow" };

// ============ 工作流事件 payload ============

export interface WorkflowDefinitionPayload {
  sessionId: string;
  turnId: string;
  phases: Array<{
    id: PhaseId;
    name: string;
    description: string;
    order: number;
    status: PhaseStatus;
  }>;
  currentPhase: PhaseId;
}

export interface WorkflowPhaseStartedPayload {
  sessionId: string;
  turnId: string;
  phaseId: PhaseId;
  phaseName: string;
  phaseOrder: number;
}

export interface WorkflowPhaseCompletedPayload {
  sessionId: string;
  turnId: string;
  phaseId: PhaseId;
  phaseName: string;
  status: PhaseStatus;
  summary?: string;
  availableActions: string[];
  canRollbackTo: Array<{ phase_id: PhaseId; phase_name: string; position: number }>;
  artifactPath?: string;
}

export interface WorkflowStatusPayload {
  sessionId: string;
  turnId: string;
  status: WorkflowStatus;
  currentPhase?: PhaseId;
  executionHistory?: PhaseId[];
}

export interface WorkflowCompletedPayload {
  sessionId: string;
  turnId: string;
  phaseResults: Array<{
    phaseId: PhaseId;
    status: PhaseStatus;
    artifactPath?: string;
    tokenUsage: { input: number; output: number };
  }>;
  totalTokenUsage: { input: number; output: number };
}

export interface WorkflowRollbackPayload {
  sessionId: string;
  turnId: string;
  targetPhase: PhaseId;
  cleanedPhases: PhaseId[];
}

// ============ 新增事件 payload ============

export interface WorkflowErrorPayload {
  sessionId: string;
  turnId: string;
  error: string;
  phaseId?: PhaseId;
}

export interface WorkflowSelectBranchPayload {
  sessionId: string;
  turnId: string;
  branches: Array<{
    id: string;
    name: string;
    description: string;
  }>;
}

export interface WorkflowSkillsSelectedPayload {
  sessionId: string;
  turnId: string;
  selectedSkills: Array<{ name: string; description: string }>;
}

// ============ compilation_fix 多分支事件 payload ============

export type CompilationFixTaskType = "file_group" | "code_group";
export type CompilationFixTaskStatus = "pending" | "running" | "completed" | "failed";

export interface CompilationFixTaskBasePayload {
  sessionId: string;
  turnId: string;
  phaseId: "compilation_fix";
  taskId: string;
  roundNum: number;
  batchIndex: number;
  totalBatches: number;
  seq: number;
  timestamp: number;
}

export interface CompilationFixTaskStartedPayload extends CompilationFixTaskBasePayload {
  taskType: CompilationFixTaskType;
  taskName: string;
  description: string;
  errorCount: number;
  affectedFiles?: string[];
}

export interface CompilationFixTaskStatusPayload extends CompilationFixTaskBasePayload {
  status: CompilationFixTaskStatus;
  progress?: number;
  message?: string;
}

export interface CompilationFixTaskCompletedPayload extends CompilationFixTaskBasePayload {
  taskType: CompilationFixTaskType;
  success: boolean;
  fixedCount: number;
  remainingCount: number;
  durationMs: number;
  errorMessage?: string;
}
